from collections import defaultdict

class Trie:
    def __init__(self):
        self.children = defaultdict(Trie)
        self.is_end = False
    def insert(self, word):
        node = self
        for ch in word:
            node = node.children[ch]
        node.is_end = True
    def search(self, word):
        node = self
        for ch in word:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return node.is_end

def solve(words, queries):
    t = Trie()
    for w in words: t.insert(w)
    return [t.search(q) for q in queries]
```

